SELECT
    id, user_id, user_name, user_phone, reservation_type, reservation_time, reservation_status, service_address, reject_reason, create_by, create_time, update_by, update_time, remark
FROM community_reservation
WHERE
    user_id = #{userId}
  AND user_name LIKE CONCAT('%', #{userName}, '%')
  AND user_phone = #{userPhone}
  AND reservation_type = #{reservationType}
  AND reservation_time = #{reservationTime}
  AND reservation_status = #{reservationStatus}
  AND service_address = #{serviceAddress}
  AND reject_reason = #{rejectReason}

SELECT id, user_id, user_name, user_phone, reservation_type, reservation_time, reservation_status, service_address, reject_reason, create_by, create_time, update_by, update_time, remark
FROM community_reservation
WHERE id = #{id}
